// Get Google Places data
const placesData = $('Fetch GBP Data via Places API').first().json;
const result = placesData.result || {};

// Get internal metrics
const postsData = $('Fetch Recent GBP Posts').all();
const faqsData = $('Fetch Latest FAQ Date').all();

const postCount = Array.isArray(postsData) ? postsData.length : 0;
const reviewCount = result.user_ratings_total || 0;
const rating = result.rating || 0;
const photoCount = result.photos ? result.photos.length : 0;
const hasHours = result.opening_hours ? true : false;

// FAQ freshness (days since last update)
let faqDaysSince = 999;
if (faqsData && faqsData.length > 0 && faqsData[0].json && faqsData[0].json.created_at) {
  const lastFaq = new Date(faqsData[0].json.created_at);
  faqDaysSince = Math.floor((Date.now() - lastFaq.getTime()) / (1000 * 60 * 60 * 24));
}

// Scoring rubric (100 points total)
let postScore = 0;
if (postCount >= 12) postScore = 25;
else if (postCount >= 8) postScore = 20;
else if (postCount >= 4) postScore = 15;
else if (postCount >= 1) postScore = 10;

let reviewScore = 0;
if (reviewCount >= 50) reviewScore = 20;
else if (reviewCount >= 30) reviewScore = 15;
else if (reviewCount >= 15) reviewScore = 10;
else if (reviewCount >= 5) reviewScore = 5;

let ratingScore = 0;
if (rating >= 4.5) ratingScore = 15;
else if (rating >= 4.0) ratingScore = 10;
else if (rating >= 3.5) ratingScore = 5;

let photoScore = 0;
if (photoCount >= 20) photoScore = 15;
else if (photoCount >= 10) photoScore = 10;
else if (photoCount >= 5) photoScore = 5;

let faqScore = 0;
if (faqDaysSince <= 90) faqScore = 15;
else if (faqDaysSince <= 180) faqScore = 10;

let hoursScore = hasHours ? 10 : 0;

const totalScore = postScore + reviewScore + ratingScore + photoScore + faqScore + hoursScore;

let grade;
if (totalScore >= 90) grade = 'A';
else if (totalScore >= 75) grade = 'B';
else if (totalScore >= 60) grade = 'C';
else if (totalScore >= 40) grade = 'D';
else grade = 'F';

// Generate recommendations
const recs = [];
if (postScore < 25) recs.push('Increase posting frequency - aim for 12+ posts/month');
if (reviewScore < 20) recs.push(`Get more reviews - currently at ${reviewCount}, target 50+`);
if (ratingScore < 15) recs.push(`Improve rating - currently ${rating}, target 4.5+`);
if (photoScore < 15) recs.push(`Add more photos - currently ${photoCount}, target 20+`);
if (faqScore < 15) recs.push('Update FAQs - run FAQ rotation or update manually');
if (hoursScore < 10) recs.push('Add business hours to your GBP profile');
if (recs.length === 0) recs.push('Profile is fully optimized! Keep it up.');

const now = new Date();
const monthName = now.toLocaleString('en-US', { month: 'long' });
const year = now.getFullYear();

// Build Telegram report
const trendArrow = '\u2796'; // neutral for first run
let report = `\ud83d\udcca GBP OPTIMIZATION REPORT - ${monthName} ${year}\n\n`;
report += `Overall Score: ${totalScore}/100 (${grade})\n`;
report += `${trendArrow} First audit (no prior data)\n\n`;
report += `Breakdown:\n`;
report += `\ud83d\udcdd Posts (25): ${postScore}/25 (${postCount} posts in 30d)\n`;
report += `\u2b50 Reviews (20): ${reviewScore}/20 (${reviewCount} reviews)\n`;
report += `\ud83c\udf1f Rating (15): ${ratingScore}/15 (${rating} stars)\n`;
report += `\ud83d\udcf7 Photos (15): ${photoScore}/15 (${photoCount} photos)\n`;
report += `\u2753 FAQ Freshness (15): ${faqScore}/15 (${faqDaysSince < 999 ? faqDaysSince + ' days ago' : 'never'})\n`;
report += `\u23f0 Hours (10): ${hoursScore}/10\n\n`;
report += `Recommendations:\n`;
recs.forEach(r => report += `\u2022 ${r}\n`);

const breakdown = {
  posts: { score: postScore, max: 25, value: postCount },
  reviews: { score: reviewScore, max: 20, value: reviewCount },
  rating: { score: ratingScore, max: 15, value: rating },
  photos: { score: photoScore, max: 15, value: photoCount },
  faq_freshness: { score: faqScore, max: 15, days_since: faqDaysSince },
  hours: { score: hoursScore, max: 10, present: hasHours }
};

return [{ json: {
  score: totalScore,
  grade,
  breakdown,
  review_count: reviewCount,
  review_rating: rating,
  post_count_30d: postCount,
  telegramReport: report,
  recommendations: recs
} }];
